final:
module counter (
  input clk,
  input reset,
  input en,
  output reg [3:0] count
);

  always @(posedge clk) begin
    if (reset) count <= 4'b0;
    else if (en) count <= count + 1;
  end

  always @(*) begin
    if (1'b0) begin
      if (reset) count <= 4'b0; else if (!en) count <= count - 1;
    end
  end

endmodule
